import java.util.*;

class Order {
    int id;
    String status;
    double total;
    Order(int id, String status, double total) {
        this.id = id; this.status = status; this.total = total;
    }
}

public class App {
    public static void main(String[] args) {
        List<Order> orders = new ArrayList<>(Arrays.asList(
            new Order(1, "ACTIVE", 599.0),
            new Order(2, "CANCELLED", 1200.0),
            new Order(3, "ACTIVE", 75.0),
            new Order(4, "ACTIVE", 1800.0),
            new Order(5, "ACTIVE", 74.0)
        ));

        int cancelledCount = 0;
        double smallRefund = 0;

        Iterator<Order> it = orders.iterator();
        while (it.hasNext()) {
            Order o = it.next();
            if (o.status.equals("CANCELLED")) {
                cancelledCount++;
                it.remove();
            } else if (o.total < 100) {
                smallRefund += o.total;
                it.remove();
            }
        }

        System.out.println("Cancelled: " + cancelledCount);
        System.out.println("Small order refunds: ₹" + smallRefund);
        System.out.println("Remaining orders: " + orders.size());
    }
}

