import java.util.*;

class Player implements Comparable<Player> {
    String name;
    int score;
    Player(String name, int score) { this.name = name; this.score = score; }
    @Override public int compareTo(Player o) { return Integer.compare(this.score, o.score); }
    @Override public String toString() { return name + "(" + score + ")"; }
}

class Leaderboard {
    private List<Player> players = new ArrayList<>();

    public void addPlayer(Player p) { players.add(p); }

    public List<Player> getTopPlayers(int n) {
        List<Player> sorted = new ArrayList<>(players);
        sorted.sort(Collections.reverseOrder());
        List<Player> top = sorted.subList(0, Math.min(n, sorted.size()));
        return Collections.unmodifiableList(new ArrayList<>(top));
    }

    public List<Player> getBottomPlayers(int n) {
        List<Player> sorted = new ArrayList<>(players);
        Collections.sort(sorted);
        List<Player> bottom = sorted.subList(0, Math.min(n, sorted.size()));
        return Collections.unmodifiableList(new ArrayList<>(bottom));
    }

    public void printStats() {
        if (players.isEmpty()) return;
        Player best = Collections.max(players);
        Player worst = Collections.min(players);
        System.out.println("Min score: " + worst.score + ", Max: " + best.score);
        int freq = 0;
        for (Player p : players) if (p.score == 7800) freq++;
        System.out.println("Occurrences of score 7800: " + freq);
    }
}

public class App {
    public static void main(String[] args) {
        Leaderboard lb = new Leaderboard();
        lb.addPlayer(new Player("Priya", 7800));
        lb.addPlayer(new Player("Aisha", 9500));
        lb.addPlayer(new Player("Anita", 6500));
        lb.addPlayer(new Player("Raj", 8200));
        lb.addPlayer(new Player("Vikram", 7200));

        System.out.println("Top 3: " + lb.getTopPlayers(3));
        System.out.println("Bottom 2: " + lb.getBottomPlayers(2));
        lb.printStats();
    }
}

import java.util.*;

class Product {
    String name, category;
    int stock;
    double price;

    Product(String name, String category, int stock, double price) {
        this.name = name; this.category = category;
        this.stock = stock; this.price = price;
    }

    Product withPrice(double newPrice) {
        return new Product(name, category, stock, newPrice);
    }

    public String toString() { return name + ": ₹" + String.format("%.2f", price); }
}

class InventoryCleaner {

    public int removeOutOfStock(List<Product> products) {
        int count = 0;
        Iterator<Product> it = products.iterator();
        while (it.hasNext()) {
            if (it.next().stock == 0) { count++; it.remove(); }
        }
        return count;
    }

    public List<Product> expensiveItems(List<Product> products, double threshold) {
        List<Product> expensive = new ArrayList<>();
        for (Product p : products) {
            if (p.price > threshold) expensive.add(p);
        }

        // Apply 15% discount via ListIterator
        ListIterator<Product> lit = expensive.listIterator();
        while (lit.hasNext()) {
            Product p = lit.next();
            lit.set(p.withPrice(p.price * 0.85));
        }
        return expensive;
    }

    public void consolidate(List<Product> products) {
        Set<String> seen = new HashSet<>();
        Iterator<Product> it = products.iterator();
        while (it.hasNext()) {
            Product p = it.next();
            if (!seen.add(p.name)) {  // add returns false if already present
                it.remove();
            }
        }
    }
}

public class App {
    public static void main(String[] args) {
        List<Product> inventory = new ArrayList<>(Arrays.asList(
            new Product("Mouse", "Electronics", 45, 799.0),
            new Product("Keyboard", "Electronics", 0, 1999.0),
            new Product("Monitor", "Electronics", 8, 18999.0),
            new Product("USB Hub", "Electronics", 0, 499.0),
            new Product("Mouse", "Electronics", 20, 849.0),
            new Product("Monitor", "Electronics", 5, 19999.0)
        ));

        InventoryCleaner cleaner = new InventoryCleaner();

        int removed = cleaner.removeOutOfStock(inventory);
        System.out.println("Removed out-of-stock: " + removed);

        List<Product> discounted = cleaner.expensiveItems(inventory, 1000);
        System.out.println("Discounted expensive items: " + discounted);

        cleaner.consolidate(inventory);
        System.out.println("After consolidation: " + inventory.size() + " unique products");
    }
}
